// TypeScript implementation for Function Overloads
interface FunctionOverloadsPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processFunctionOverloads(item: FunctionOverloadsPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processFunctionOverloads({ id: 1, title: 'Function Overloads', status: 'active' }));

